            return datetime.strptime(date_str, '%d %b %Y, %H:%M')
        # Format: "29 May 2013, 23:01"
        elif ',' in date_str and len(date_str.split()) == 4:
            return datetime.strptime(date_str, '%d %b %Y, %H:%M')
    except:
        return None

print("__RESULT__:")
print(json.dumps({"sample_parsing": [{"date": r["date"], "parsed": parse_date(r["date"]) is not None} for r in reviews_preview]}))

